sql:
SELECT boat_name, hcap
FROM boats
WHERE hcap = (SELECT MAX(hcap) FROM boats);

SELECT AVG(speed) AS average_speed
FROM real_time_data
WHERE boat_id = 1 AND race_id = 1;

SELECT race_id, boat_id, finish_time, corrected_time
FROM race_results
WHERE finish_time = (SELECT MAX(finish_time) FROM race_results);

SELECT boat_id, MAX(speed) AS max_speed
FROM real_time_data
GROUP BY boat_id;

external_knowledge:
- 'champions of the track' refers to the boats that finished first in each race (i.e., those with a rank of 1); 
- 'finishing times' refers to the corrected time of the boats; 
- 'overall pace' refers to the average speed of the boats during the races.
